if !expr.span.from_expansion()
            && let Some((lhs, rhs)) = unexpanded_binop_operands(expr, BinOpKind::Eq)
        {
            if is_integer_literal(rhs, 1)
                && let Some(a) = count_ones_receiver(cx, lhs)
            {
                self.build_sugg(cx, expr, a);
            } else if is_integer_literal(lhs, 1)
                && let Some(a) = count_ones_receiver(cx, rhs)
            {
                self.build_sugg(cx, expr, a);
            } else if is_integer_literal(rhs, 0)
                && let Some(a) = is_and_minus_one(cx, lhs)
            {
                self.build_sugg(cx, expr, a);
            } else if is_integer_literal(lhs, 0)
                && let Some(a) = is_and_minus_one(cx, rhs)
            {
                self.build_sugg(cx, expr, a);
            }
        }

match parent_expr.kind {
    ExprKind::MethodCall(_, receiver, exprs, _) => std::iter::once(receiver)
        .chain(exprs.iter())
        .find_position(|ex| ex.hir_id == expr.hir_id)
        .map(|(idx, _)| idx),
    ExprKind::Call(_, exprs) => exprs
        .iter()
        .find_position(|ex| ex.hir_id == expr.hir_id)
        .map(|(idx, _)| idx),
    ExprKind::Binary(_, lhs, rhs) | ExprKind::AssignOp(_, lhs, rhs) => [lhs, rhs]
        .iter()
        .find_position(|ex| ex.hir_id == expr.hir_id)
        .map(|(idx, _)| idx),
    ExprKind::Unary(_, ex) => (ex.hir_id == expr.hir_id).then_some(0),
    _ => {
        // Here we assume that all other expressions create or propagate the reference to the value with
        // significant drop.
        self.sig_drop_holder = SigDropHolder::DirectRef;
        return;
    },
}

if cx.ty_based_def(expr).opt_parent(cx).is_diag_item(cx, sym::Iterator)
        && cx.ty_based_def(recv).opt_parent(cx).is_diag_item(cx, sym::Iterator)
        && is_expr_identity_function(cx, any_arg)
        && let map_any_call_span = map_call_span.with_hi(any_call_span.hi())
        && let Some(map_arg) = map_arg.span.get_source_text(cx)
    {
        span_lint_and_then(
            cx,
            MAP_ALL_ANY_IDENTITY,
            map_any_call_span,
            format!("usage of `.map(...).{method}(identity)`"),
            |diag| {
                diag.span_suggestion_verbose(
                    map_any_call_span,
                    format!("use `.{method}(...)` instead"),
                    format!("{method}({map_arg})"),
                    Applicability::MachineApplicable,
                );
            },
        );
    }

if let ty::ReBound(ty::BoundVarIndexKind::Bound(binder), old_bound) = re.kind()
            && self.binder == binder
        {
            let mapped = if let Some(mapped) = self.mapping.get(&old_bound.var) {
                mapped.expect_region()
            } else {
                let var = ty::BoundVar::from_usize(self.still_bound_vars.len());
                self.still_bound_vars.push(ty::BoundVariableKind::Region(old_bound.kind));
                let mapped = ty::Region::new_bound(
                    self.tcx,
                    ty::INNERMOST,
                    ty::BoundRegion { var, kind: old_bound.kind },
                );
                self.mapping.insert(old_bound.var, mapped.into());
                mapped
            };

            shift_vars(self.tcx, mapped, self.binder.as_u32())
        } else {
            re
        }

if let ExprKind::Closure(&Closure { body, fn_decl_span, .. }) = arg.kind
        && let ty::Closure(_def_id, args) = &cx.typeck_results().node_type(arg.hir_id).kind()
        && let ret_ty = args.as_closure().sig().output()
        && let ty = cx.tcx.instantiate_bound_regions_with_erased(ret_ty)
        && ty.is_unit()
    {
        let body = cx.tcx.hir_body(body);
        if let ExprKind::Block(block, _) = body.value.kind
            && block.expr.is_none()
            && let Some(stmt) = block.stmts.last()
            && let StmtKind::Semi(_) = stmt.kind
        {
            let data = stmt.span.data();
            // Make a span out of the semicolon for the help message
            Some((fn_decl_span, Some(data.with_lo(data.hi - BytePos(1)))))
        } else {
            Some((fn_decl_span, None))
        }
    } else {
        None
    }

if let Some(inner_type) = &t.inner_type {
    items.push(LinkBlock::forced(Link::new("aliased-type", "Aliased Type"), "type"));
    match inner_type {
        clean::TypeAliasInnerType::Enum { variants, is_non_exhaustive: _ } => {
            let mut variants = variants
                .iter()
                .filter(|i| !i.is_stripped())
                .filter_map(|v| v.name)
                .map(|name| Link::new(format!("variant.{name}"), name.to_string()))
                .collect::<Vec<_>>();
            variants.sort_unstable();

            items.push(LinkBlock::new(Link::new("variants", "Variants"), "variant", variants));
        }
        clean::TypeAliasInnerType::Union { fields }
        | clean::TypeAliasInnerType::Struct { ctor_kind: _, fields } => {
            let fields = get_struct_fields_name(fields);
            items.push(LinkBlock::new(Link::new("fields", "Fields"), "field", fields));
        }
    }
}

match def {
    GenericDefId::ImplId(id) => {
        result.push(db.impl_self_ty_with_diagnostics(id).defined_anon_consts());
        if let Some(trait_ref) = db.impl_trait_with_diagnostics(id) {
            result.push(trait_ref.defined_anon_consts());
        }
    }
    GenericDefId::TypeAliasId(id) => {
        result.push(db.type_for_type_alias_with_diagnostics(id).defined_anon_consts());
        result.push(db.type_alias_bounds_with_diagnostics(id).defined_anon_consts());
    }
    GenericDefId::FunctionId(id) => result
        .push(db.callable_item_signature_with_diagnostics(id.into()).defined_anon_consts()),
    GenericDefId::ConstId(def) => {
        result.push(db.type_for_const_with_diagnostics(def).defined_anon_consts())
    }
    GenericDefId::StaticId(def) => {
        result.push(db.type_for_static_with_diagnostics(def).defined_anon_consts())
    }
    GenericDefId::TraitId(_) | GenericDefId::AdtId(_) => {}
}

match expr.kind {
    ExprKind::Binary(_, lhs, rhs) => {
        binops_with_local(cx, local_expr, lhs) || binops_with_local(cx, local_expr, rhs)
    },
    ExprKind::MethodCall(path, receiver, [arg], _)
        if path.ident.name == sym::contains
            // ... `contains` called on some kind of range
            && let Some(receiver_adt) = cx.typeck_results().expr_ty(receiver).peel_refs().ty_adt_def()
            && let lang_items = cx.tcx.lang_items()
            && [
                lang_items.range_from_struct(),
                lang_items.range_inclusive_struct(),
                lang_items.range_struct(),
                lang_items.range_to_inclusive_struct(),
                lang_items.range_to_struct()
            ].into_iter().any(|did| did == Some(receiver_adt.did())) =>
    {
        eq_expr_value(cx, SyntaxContext::root(), local_expr, arg.peel_borrows())
    },
    _ => eq_expr_value(cx, SyntaxContext::root(), local_expr, expr),
}

if let Some(inner_expr_ty) = option_arg_ty(cx, cx.typeck_results().expr_ty(expr))
        && arms.len() == 2
        && arms.iter().all(|arm| arm.guard.is_none())
        && let Some((idx, is_ok)) = arms.iter().enumerate().find_map(|(arm_idx, arm)| {
            // Check if the arm is a `Ok(x) => x` or `Err(x) => x` alternative.
            // In this case, return its index and whether it uses `Ok` or `Err`.
             if let Some((is_ok, ident)) = is_ok_or_err(cx, arm.pat)
                && is_some_ident(cx, arm.body, ident, inner_expr_ty)
            {
                Some((arm_idx, is_ok))
            } else {
                None
            }
        })
        // Accept wildcard only as the second arm
        && is_variant_or_wildcard(cx, arms[1-idx].pat, idx == 0, is_ok)
        // Check that the body of the non `Ok`/`Err` arm is `None`
        && is_none(cx, arms[1 - idx].body)
    {
        apply_lint(cx, expr, scrutinee, is_ok);
    }

if let hir::ExprKind::Match(await_expr, _arms, hir::MatchSource::AwaitDesugar) = expr.kind
            && let ty = cx.typeck_results().expr_ty(await_expr)
            && let ty::Alias(ty::AliasTy { kind: ty::Opaque { def_id: future_def_id }, .. }) = ty.kind()
            && cx.tcx.ty_is_opaque_future(ty)
            && let async_fn_def_id = cx.tcx.parent(*future_def_id)
            && matches!(cx.tcx.def_kind(async_fn_def_id), DefKind::Fn | DefKind::AssocFn)
            // Check that this `impl Future` actually comes from an `async fn`
            && cx.tcx.asyncness(async_fn_def_id).is_async()
            && check_must_use_def(
                cx,
                async_fn_def_id,
                expr.span,
                "output of future returned by ",
                "",
                expr_is_from_block,
            )
        {
            // We have a bare `foo().await;` on an opaque type from an async function that was
            // annotated with `#[must_use]`.
            return;
        }

if let StmtKind::Semi(expr) = stmt.kind
            && let ExprKind::Binary(binop, a, b) = &expr.kind
            && matches!(binop.node, BinOpKind::And | BinOpKind::Or)
            && !stmt.span.from_expansion()
            && expr.span.eq_ctxt(stmt.span)
        {
            span_lint_hir_and_then(
                cx,
                SHORT_CIRCUIT_STATEMENT,
                expr.hir_id,
                stmt.span,
                "boolean short circuit operator in statement may be clearer using an explicit test",
                |diag| {
                    let mut app = Applicability::MachineApplicable;
                    let test = Sugg::hir_with_context(cx, a, expr.span.ctxt(), "_", &mut app);
                    let test = if binop.node == BinOpKind::Or { !test } else { test };
                    let then = Sugg::hir_with_context(cx, b, expr.span.ctxt(), "_", &mut app);
                    diag.span_suggestion(stmt.span, "replace it with", format!("if {test} {{ {then}; }}"), app);
                },
            );
        }

match expr.kind {
    ExprKind::Call(
        Expr {
            kind: ExprKind::Path(some_path),
            hir_id: some_hir_id,
