}

if let Some(conv) = should_use_fp_conv(cx, &arg.layout, xlen, flen) {
    match conv {
        FloatConv::Float(f) => {
            arg.cast_to(f);
        }
        FloatConv::FloatPair { first_ty, second_ty_offset_from_start, second_ty } => {
            arg.cast_to(CastTarget::offset_pair(
                first_ty,
                second_ty_offset_from_start,
                second_ty,
            ));
        }
        FloatConv::MixedPair { first_ty, second_ty_offset_from_start, second_ty } => {
            arg.cast_to(CastTarget::offset_pair(
                first_ty,
                second_ty_offset_from_start,
                second_ty,
            ));
        }
    }
    return false;
}

if let ExprKind::Cast(inner, ..) = expr.kind
        && let ExprKind::Path(qpath) = inner.kind
        && let QPath::Resolved(None, Path { res, .. }) = qpath
        && let Res::Local(hir_id) = res
        && let parent = cx.tcx.parent_hir_node(*hir_id)
        && let Node::LetStmt(local) = parent
    {
        if let Some(ty) = local.ty
            && let TyKind::Path(qpath) = ty.kind
