match parse_args(ecx, sp, tts, AsmMacro::Asm) {
    Ok(args) => {
        let ExpandResult::Ready(mac) = expand_preparsed_asm(ecx, AsmMacro::Asm, args) else {
            return ExpandResult::Retry(());
        };
        let expr = match mac {
            Ok(inline_asm) => Box::new(ast::Expr {
                id: ast::DUMMY_NODE_ID,
                kind: ast::ExprKind::InlineAsm(Box::new(inline_asm)),
                span: sp,
                attrs: ast::AttrVec::new(),
                tokens: None,
            }),
            Err(guar) => DummyResult::raw_expr(sp, Some(guar)),
        };
        MacEager::expr(expr)
    }
    Err(err) => {
        let guar = err.emit();
        DummyResult::any(sp, guar)
    }
}

match t.kind() {
    ty::Uint(ty::UintTy::Usize) | ty::Int(ty::IntTy::Isize) => None,
    ty::Uint(_) => Some(Integer::fit_unsigned(val).uint_ty_str()),
    ty::Int(_) => {
        let signed = literal_to_i128(val, negative).map(Integer::fit_signed);
        if negative {
            signed.map(Integer::int_ty_str)
        } else {
            let unsigned = Integer::fit_unsigned(val);
            Some(if let Some(signed) = signed {
                if unsigned.size() < signed.size() {
                    unsigned.uint_ty_str()
                } else {
                    signed.int_ty_str()
                }
            } else {
                unsigned.uint_ty_str()
            })
        }
    }
    _ => None,
}

match *rvalue {
    Rvalue::ThreadLocalRef(_) => {} // not-a-move
    Rvalue::Use(ref operand, _)
    | Rvalue::Repeat(ref operand, _)
    | Rvalue::Cast(_, ref operand, _)
    | Rvalue::UnaryOp(_, ref operand)
    | Rvalue::WrapUnsafeBinder(ref operand, _) => self.gather_operand(operand),
    Rvalue::BinaryOp(ref _binop, (ref lhs, ref rhs)) => {
        self.gather_operand(lhs);
        self.gather_operand(rhs);
    }
    Rvalue::Aggregate(ref _kind, ref operands) => {
        for operand in operands {
            self.gather_operand(operand);
        }
    }
    Rvalue::CopyForDeref(..) => unreachable!(),
    Rvalue::Ref(..)
    | Rvalue::Reborrow(..)
    | Rvalue::RawPtr(..)
    | Rvalue::Discriminant(..) => {}
}

if !cfg_info.auto_cfg_active && !cfg_info.parent_is_doc_cfg {
    None
} else if cfg_info.parent_is_doc_cfg {
    if matches!(cfg_info.current_cfg.0, CfgEntry::Bool(true, _)) {
        None
    } else {
        let mut cfg = cfg_info.current_cfg.clone();
        cfg.sort_for_rendering();
        Some(Arc::new(cfg))
    }
} else {
    // If `doc(auto_cfg)` feature is enabled, we want to collect all `cfg` items, we remove the
    // hidden ones afterward.
    match strip_hidden(&cfg_info.current_cfg.0, &cfg_info.hidden_cfg) {
        None | Some(CfgEntry::Bool(true, _)) => None,
        Some(cfg_entry) => {
            let mut cfg = Cfg(cfg_entry);
            cfg.sort_for_rendering();
            Some(Arc::new(cfg))
        }
    }
}

if let Some(global) = this.machine.data_race.as_vclocks_ref() {
    if atomic == AtomicReadOrd::SeqCst {
        global.sc_read(&this.machine.threads);
    }
    let size = place.layout.size;
    let (alloc_id, base_offset, ..) = this.ptr_get_alloc_id(place.ptr(), 0)?;
    if let Some(alloc_buffers) =
        this.get_alloc_extra(alloc_id)?.data_race.as_weak_memory_ref()
    {
        let Some(buffer) =
            alloc_buffers.get_store_buffer(alloc_range(base_offset, size))?
        else {
            // No store buffer, nothing to do.
            return interp_ok(());
        };
        buffer.read_from_last_store(
            global,
            &this.machine.threads,
            atomic == AtomicReadOrd::SeqCst,
        );
    }
}

while let Some(id) = locals_to_check.pop() {
    if let Node::LetStmt(l) = cx.tcx.parent_hir_node(id) {
        if !l.ty.is_none_or(|ty| matches!(ty.kind, TyKind::Infer(()))) {
            return false;
        }
        if let Some(e) = l.init {
            if !each_value_source_needs_inference(cx, e, &mut locals_to_check, &mut seen_locals) {
                return false;
            }
        } else if for_each_local_assignment(cx, id, |e| {
            if each_value_source_needs_inference(cx, e, &mut locals_to_check, &mut seen_locals) {
                ControlFlow::Continue(())
            } else {
                ControlFlow::Break(())
            }
        })
        .is_break()
        {
            return false;
        }
    }
}

match def_key.disambiguated_data.data {
    DefPathData::CrateRoot => {
        crate_name = self.tcx.crate_name(def_id.krate);
        name = crate_name.as_str();
        dis = "";
        end_index = 3;
    }
    other => {
        other_name = other.to_string();
        name = other_name.as_str();
        if def_key.disambiguated_data.disambiguator == 0 {
            dis = "";
            end_index = 3;
        } else {
            write!(&mut dis_buffer[..], "[{}]", def_key.disambiguated_data.disambiguator)
                .unwrap();
            let end_of_dis = dis_buffer.iter().position(|&c| c == b']').unwrap();
            dis = std::str::from_utf8(&dis_buffer[..end_of_dis + 1]).unwrap();
            end_index = 4;
        }
    }
}

match dlltool_cmd.output() {
    Err(e) => {
        sess.dcx().emit_fatal(ErrorCallingDllTool {
            dlltool_path: dlltool.to_string_lossy(),
            error: e,
        });
    }
    // dlltool returns '0' on failure, so check for error output instead.
    Ok(output) if !output.stderr.is_empty() => {
        sess.dcx().emit_fatal(DlltoolFailImportLibrary {
            dlltool_path: dlltool.to_string_lossy(),
            dlltool_args: dlltool_cmd
                .get_args()
                .map(|arg| arg.to_string_lossy())
                .collect::<Vec<_>>()
                .join(" "),
            stdout: String::from_utf8_lossy(&output.stdout),
            stderr: String::from_utf8_lossy(&output.stderr),
        })
    }
    _ => {}
}

loop {
    unsafe {
        let ptr = buf.as_mut_ptr() as *mut libc::c_char;
        if !libc::getcwd(ptr, buf.capacity()).is_null() {
            let len = CStr::from_ptr(buf.as_ptr() as *const libc::c_char).to_bytes().len();
            buf.set_len(len);
            buf.shrink_to_fit();
            return Ok(PathBuf::from(OsString::from_vec(buf)));
        } else {
            let error = io::Error::last_os_error();
            if error.raw_os_error() != Some(libc::ERANGE) {
                return Err(error);
            }
        }

        // Trigger the internal buffer resizing logic of `Vec` by requiring
        // more space than the current capacity.
        let cap = buf.capacity();
        buf.set_len(cap);
        buf.reserve(1);
    }
}

loop {
    print!("{prompt_str}");
    io::stdout().flush()?;
    io::stdin().read_line(&mut input)?;

    let mut modified_input = input.to_lowercase();
    modified_input.retain(|ch| !ch.is_whitespace());
    match modified_input.as_str() {
        "1" | "emacs" => return Ok(Some(EditorKind::Emacs)),
        "2" | "helix" => return Ok(Some(EditorKind::Helix)),
        "3" | "vim" => return Ok(Some(EditorKind::Vim)),
        "4" | "vscode" => return Ok(Some(EditorKind::VsCode)),
        "5" | "zed" => return Ok(Some(EditorKind::Zed)),
        "" | "none" => return Ok(None),
        _ => {
            eprintln!("ERROR: unrecognized option '{}'", input.trim());
            eprintln!("NOTE: press Ctrl+C to exit");
        }
    }

    input.clear();
}

if let Some(eq_token) = ctx.find_token_syntax_at_offset(T![=]) {
    let parent = eq_token.parent()?;
    let body = match_ast! {
        match parent {
            ast::LetStmt(it) => it.initializer()?,
            ast::LetExpr(it) => it.expr()?,
            ast::BinExpr(it) => it.rhs()?,
            ast::Static(it) => it.body()?,
            ast::Const(it) => it.body()?,
            _ => return None,
        }
    };
    (ParentType::Assignment, body)
} else if let Some(Either::Left(match_arm)) = &node {
    let match_arm_expr = match_arm.expr()?;
    (ParentType::MatchArmExpr, match_arm_expr)
} else if let Some(Either::Right(closure_expr)) = &node {
    let body = closure_expr.body()?;
    (ParentType::ClosureExpr, body)
} else {
    return None;
}
